import { Logtail } from '@logtail/edge'
import type { Bindings } from '../env'

let baseLogtail: Logtail | undefined

export function isLogtailEnabled(env: Bindings): boolean {
  return Boolean(env.LOGTAIL_SOURCE_TOKEN && env.LOGTAIL_ENDPOINT)
}

export function getBaseLogtail(env: Bindings): Logtail | undefined {
  if (!isLogtailEnabled(env)) {
    return undefined
  }

  if (!baseLogtail) {
    baseLogtail = new Logtail(env.LOGTAIL_SOURCE_TOKEN!, {
      endpoint: env.LOGTAIL_ENDPOINT!,
    })
  }

  return baseLogtail
}

import type { EdgeWithExecutionContext } from '@logtail/edge/dist/es6/edgeWithExecutionContext.js'
import { LogLevel } from '@logtail/types'
import type { Context, StackContextHint } from '@logtail/types'

const PINO_RESERVED_KEYS = new Set(['time', 'msg', 'message', 'level', 'v'])

const stackContextHint: StackContextHint = {
  fileName: 'node_modules/pino',
  methodNames: ['log', 'fatal', 'error', 'warn', 'info', 'debug', 'trace', 'silent'],
  required: true,
}

interface PinoLogLine {
  level: number
  time?: string | number
  msg?: string
  message?: string
  reqId?: string | number
  [key: string]: unknown
}

function getLogLevel(level: number): LogLevel {
  if (level <= 10) {
    return LogLevel.Trace
  }
  if (level <= 20) {
    return LogLevel.Debug
  }
  if (level <= 30) {
    return LogLevel.Info
  }
  if (level <= 40) {
    return LogLevel.Warn
  }
  if (level <= 50) {
    return LogLevel.Error
  }
  return LogLevel.Fatal
}

function getRequestId(obj: PinoLogLine): string | undefined {
  const reqId = obj.reqId
  if (reqId === undefined || reqId === null) {
    return undefined
  }
  return String(reqId)
}

function forwardToLogtail(logger: EdgeWithExecutionContext, obj: PinoLogLine): void {
  const meta: Context = {}

  if (typeof obj.time === 'string' && obj.time.length > 0) {
    const time = new Date(obj.time)
    if (!Number.isNaN(time.valueOf())) {
      meta.dt = time
    }
  }

  for (const key of Object.keys(obj)) {
    if (!PINO_RESERVED_KEYS.has(key)) {
      meta[key] = obj[key]
    }
  }

  const msg = obj.msg ?? obj.message
  if (msg === undefined) {
    return
  }

  if (obj.msg !== undefined && obj.message !== undefined) {
    meta.message_field = obj.message
  }

  let level: LogLevel
  try {
    level = getLogLevel(obj.level)
  } catch {
    console.error('Error while mapping log level.')
    return
  }

  void logger.log(msg, level, meta, stackContextHint)
}

export function createLogtailBrowserWrite(
  getLogger: (requestId: string) => EdgeWithExecutionContext | undefined,
  options?: { mirrorToConsole?: boolean },
) {
  const mirrorToConsole = options?.mirrorToConsole ?? true

  return (msg: string) => {
    if (mirrorToConsole) {
      console.log(msg)
    }

    let obj: PinoLogLine
    try {
      obj = JSON.parse(msg) as PinoLogLine
    } catch {
      return
    }

    const requestId = getRequestId(obj)
    if (!requestId) {
      return
    }

    const logger = getLogger(requestId)
    if (!logger) {
      return
    }

    forwardToLogtail(logger, obj)
  }
}

