import type { Logtail } from '@logtail/edge'
import { createMiddleware } from 'hono/factory'
import type { AppEnv } from '../env'
import { getBaseLogtail, isLogtailEnabled } from '../lib/logtail'

type RequestLogtail = ReturnType<Logtail['withExecutionContext']>

type RequestLogContext = {
  logger: RequestLogtail
  minLevel: number
}

const logContextByRequestId = new Map<string, RequestLogContext>()

const PINO_LEVELS: Record<string, number> = {
  trace: 10,
  debug: 20,
  info: 30,
  warn: 40,
  error: 50,
  fatal: 60,
  silent: 100,
}

function toPinoLevel(logLevel?: string): number {
  if (!logLevel) {
    return PINO_LEVELS.info
  }
  return PINO_LEVELS[logLevel] ?? PINO_LEVELS.info
}

export function getRequestLogContext(requestId: string): RequestLogContext | undefined {
  return logContextByRequestId.get(requestId)
}

export const logtailRegistryMiddleware = createMiddleware<AppEnv>(async (c, next) => {
  const requestId = c.get('requestId')
  const minLevel = toPinoLevel(c.env.LOG_LEVEL)

  if (!isLogtailEnabled(c.env)) {
    logContextByRequestId.set(requestId, {
      logger: undefined as unknown as RequestLogtail,
      minLevel,
    })

    try {
      await next()
    } finally {
      logContextByRequestId.delete(requestId)
    }
    return
  }

  const base = getBaseLogtail(c.env)
  if (!base) {
    await next()
    return
  }

  logContextByRequestId.set(requestId, {
    logger: base.withExecutionContext(c.executionCtx),
    minLevel,
  })

  try {
    await next()
  } finally {
    logContextByRequestId.delete(requestId)
  }
})

